package com.google.gson;

import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonToken;
import com.google.gson.JsonIOException;
import com.google.gson.JsonSyntaxException;
import com.google.gson.stream.MalformedJsonException;
import org.junit.jupiter.api.Test;

import java.io.IOException;
import java.lang.reflect.Method;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

class GsonAssertFullConsumptionTest {

  @Test
  void testAssertFullConsumption_objNull_shouldNotThrow() throws Exception {
    JsonReader reader = mock(JsonReader.class);
    when(reader.peek()).thenReturn(JsonToken.BEGIN_OBJECT);
    invokeAssertFullConsumption(null, reader);
  }

  @Test
  void testAssertFullConsumption_objNotNull_andPeekIsEndDocument_shouldNotThrow() throws Exception {
    JsonReader reader = mock(JsonReader.class);
    when(reader.peek()).thenReturn(JsonToken.END_DOCUMENT);
    invokeAssertFullConsumption(new Object(), reader);
  }

  @Test
  void testAssertFullConsumption_objNotNull_andPeekIsNotEndDocument_shouldThrowJsonSyntaxException() throws Exception {
    JsonReader reader = mock(JsonReader.class);
    when(reader.peek()).thenReturn(JsonToken.BEGIN_ARRAY);
    JsonSyntaxException ex = assertThrows(JsonSyntaxException.class, () -> invokeAssertFullConsumption(new Object(), reader));
    assertEquals("JSON document was not fully consumed.", ex.getMessage());
  }

  @Test
  void testAssertFullConsumption_malformedJsonException_shouldThrowJsonSyntaxException() throws Exception {
    JsonReader reader = mock(JsonReader.class);
    when(reader.peek()).thenThrow(new MalformedJsonException("malformed"));
    JsonSyntaxException ex = assertThrows(JsonSyntaxException.class, () -> invokeAssertFullConsumption(new Object(), reader));
    assertTrue(ex.getCause() instanceof MalformedJsonException);
    assertEquals("malformed", ex.getCause().getMessage());
  }

  @Test
  void testAssertFullConsumption_ioException_shouldThrowJsonIOException() throws Exception {
    JsonReader reader = mock(JsonReader.class);
    when(reader.peek()).thenThrow(new IOException("io error"));
    JsonIOException ex = assertThrows(JsonIOException.class, () -> invokeAssertFullConsumption(new Object(), reader));
    assertTrue(ex.getCause() instanceof IOException);
    assertEquals("io error", ex.getCause().getMessage());
  }

  private static void invokeAssertFullConsumption(Object obj, JsonReader reader) throws Exception {
    Method method = Gson.class.getDeclaredMethod("assertFullConsumption", Object.class, JsonReader.class);
    method.setAccessible(true);
    try {
      method.invoke(null, obj, reader);
    } catch (java.lang.reflect.InvocationTargetException e) {
      // unwrap the cause to throw the actual exception
      throw (Exception) e.getCause();
    }
  }
}
